  ('cpa-moex-00554', 'cpa', 'cpa-moex-110-9bdab6d6', 'sub-cpa-05', NULL, 'single_choice', '英國A大學將該大學之一套圖書資料庫透過網際網路提供給我國乙大學使用，每年該大學須支付 新臺幣（下同）525萬元給A大學，本項交易行為應如何繳納營業稅？', '["英國A大學於收取款項當期，向國稅局自動報繳25萬元營業稅", "我國乙大學於給付報酬之次期開始15日內，向國稅局報繳26.25萬元", "我國乙大學於給付報酬之次期開始15日內，向國稅局報繳25萬元", "本案免繳納營業稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "ca54d92e3b28", "answer_pdf_sha1": "5915331d0c5d", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
